function setLang(l){
  document.querySelectorAll('[data-i]').forEach(el=>{const k=el.getAttribute('data-i'); if(T[l][k]!==undefined) el.innerHTML=T[l][k];});
  document.querySelectorAll('.lang a').forEach(a=>a.classList.toggle('on',a.getAttribute('data-set')===l));
  document.documentElement.lang=l;
  try{localStorage.setItem('rg_lang',l);}catch(e){}
  if(window.quizRerender)window.quizRerender();
  if(window.reviewsRerender)window.reviewsRerender();
  if(window.cartRerender)window.cartRerender();
}
function applyTheme(t){
  document.documentElement.setAttribute('data-theme',t);
  try{localStorage.setItem('rg_theme',t);}catch(e){}
  document.querySelectorAll('.themetoggle').forEach(b=>{b.textContent=t==='dark'?'☀':'☾';b.setAttribute('aria-pressed',t==='dark');});
}
document.addEventListener('DOMContentLoaded',()=>{
  let l='en'; try{l=localStorage.getItem('rg_lang')||'en';}catch(e){}
  setLang(l);
  document.querySelectorAll('.lang a').forEach(a=>a.addEventListener('click',()=>setLang(a.getAttribute('data-set'))));
  let th='light'; try{th=localStorage.getItem('rg_theme')||(matchMedia('(prefers-color-scheme:dark)').matches?'dark':'light');}catch(e){}
  applyTheme(th);
  document.querySelectorAll('.themetoggle').forEach(b=>b.addEventListener('click',()=>applyTheme(document.documentElement.getAttribute('data-theme')==='dark'?'light':'dark')));
  initSearch();
  initReviews();
  initQuiz();
  initLookbook();
  initMaterials();
  initPDP();
  initCart();
  initNav();
  /* perf: async-decode every image, lazy-load all but the LCP product image */
  document.querySelectorAll('img').forEach(function(im){im.setAttribute('decoding','async');if(im.id!=='mainimg'&&!im.hasAttribute('loading'))im.setAttribute('loading','lazy');});
  var _lcp=document.getElementById('mainimg');if(_lcp)_lcp.setAttribute('fetchpriority','high');
});

/* ===== AI-flavored search (krok 20). Prototyp; produkcyjnie -> Shopify Search & Discovery / Algolia ===== */
const SEARCH_INDEX=[
 {t:'Cork Grip Round',syn:'round volume blowout bounce boar',price:'€24,90',img:'https://www.regincoshair.com/cdn/shop/files/Regincos_2023-3.jpg?width=300'},
 {t:'Cork Grip Large',syn:'round large long thick volume',price:'€27,90',img:'https://www.regincoshair.com/cdn/shop/products/566.jpg?width=300'},
 {t:'Cork Paddle Brush',syn:'paddle straight smooth detangle long flat',price:'€21,50',img:'https://www.regincoshair.com/cdn/shop/products/605.jpg?width=300'},
 {t:'Cork Vent Brush',syn:'vented vent fast dry frizz airflow blowdry',price:'€19,90',img:'https://www.regincoshair.com/cdn/shop/products/270.jpg?width=300'},
 {t:'Wood Paddle Brush',syn:'paddle wood straight smooth scalp',price:'€23,50',img:'https://www.regincoshair.com/cdn/shop/products/282.jpg?width=300'},
 {t:'Vegan Beard Brush',syn:'vegan beard men cruelty-free',price:'€18,00',img:'https://www.regincoshair.com/cdn/shop/products/307.jpg?width=300'}
];
const SEARCH_SYN={frizz:'vented',frizzy:'vented',frisado:'vented',dry:'vented',blowdry:'vented',volume:'round',voluminoso:'round',thick:'large',blowout:'round',straight:'paddle',liso:'paddle',smooth:'paddle',detangle:'paddle',beard:'beard',barba:'beard',men:'beard',homem:'beard',vegan:'vegan',vegana:'vegan',cruelty:'vegan',madeira:'wood',cortica:'cork'};
function searchCorpus(){
  var ls={cork:'cortiça corcho round redonda volume bounce',wood:'madeira fusta paddle oval flat',yoga:'flexible vented desenredante frizz detangle',ibiza:'thermal hybrid roller',combs:'peine comb pente',metal:'metallic',pocket:'travel pocket'};
  if(window.CATALOG&&window.CATALOG.length){return window.CATALOG.map(function(p){return {t:p.t,h:p.h,price:'€'+Number(p.p).toFixed(2).replace('.',','),img:((p.imgs&&p.imgs[0])||p.img)+'?width=300',hay:(p.t+' '+p.line+' '+(ls[p.line]||'')).toLowerCase()};});}
  return SEARCH_INDEX.map(function(p){return {t:p.t,h:'',price:p.price,img:p.img,hay:(p.t+' '+p.syn).toLowerCase()};});
}
function searchRank(q){
  q=(q||'').toLowerCase().trim();
  var corpus=searchCorpus();
  if(!q)return corpus.slice(0,5);
  var toks=q.split(/[^0-9a-zà-ú]+/).filter(Boolean);
  var exp=new Set();toks.forEach(function(t){exp.add(t);if(SEARCH_SYN[t])exp.add(SEARCH_SYN[t]);});
  return corpus.map(function(p){var s=0;exp.forEach(function(t){if(p.t.toLowerCase().indexOf(t)>=0)s+=3;else if(p.hay.indexOf(t)>=0)s+=1;});return {p:p,s:s};}).filter(function(x){return x.s>0;}).sort(function(a,b){return b.s-a.s;}).map(function(x){return x.p;});
}
function initSearch(){
  if(document.querySelector('.searchov'))return;
  const ov=document.createElement('div');ov.className='searchov';
  ov.innerHTML='<div class="searchpanel"><div class="top"><span class="ic">⌕</span><input id="sq" autocomplete="off" aria-label="Search"><button class="close" id="sclose" type="button">Esc</button></div><div class="searchhint" data-i="sr_hint"></div><div class="searchres" id="sres"></div></div>';
  document.body.appendChild(ov);
  const inp=ov.querySelector('#sq'),res=ov.querySelector('#sres');
  function loc(){return document.documentElement.lang||'en';}
  function i18n(scope){const l=loc();scope.querySelectorAll('[data-i]').forEach(el=>{const k=el.getAttribute('data-i');if(T[l]&&T[l][k]!==undefined)el.innerHTML=T[l][k];});}
  function render(){
    const list=searchRank(inp.value);
    res.innerHTML=list.length?list.map(p=>'<a class="sr" href="product.html'+(p.h?'?p='+p.h:'')+'"><img src="'+p.img+'" alt=""><span class="nm serif">'+p.t+'</span><span class="pr">'+p.price+'</span></a>').join(''):'<div class="none" data-i="sr_none"></div>';
    i18n(res);
  }
  function open(){ov.classList.add('open');inp.value='';const l=loc();if(T[l]&&T[l].sr_ph)inp.placeholder=T[l].sr_ph;i18n(ov);render();setTimeout(()=>inp.focus(),30);}
  function close(){ov.classList.remove('open');}
  inp.addEventListener('input',render);
  document.getElementById('sclose').addEventListener('click',close);
  ov.addEventListener('click',e=>{if(e.target===ov)close();});
  document.addEventListener('keydown',e=>{if(e.key==='Escape'&&ov.classList.contains('open'))close();});
  document.querySelectorAll('[title="search"]').forEach(s=>{s.style.cursor='pointer';s.setAttribute('role','button');s.setAttribute('tabindex','0');s.addEventListener('click',open);s.addEventListener('keydown',e=>{if(e.key==='Enter'||e.key===' '){e.preventDefault();open();}});});
}

/* ===== UGC reviews (krok 19). Prototyp; produkcyjnie -> Judge.me / Loox / Okendo via app blocks + metafields ===== */
const REVIEWS=[
 {n:'Marta R.',loc:'Lisboa',s:5,ht:'thick',b:'A pega de cortiça é incrível — leve e quente ao toque. Uso-a todos os dias no salão.'},
 {n:'James A.',loc:'London',s:5,ht:'fine',b:'Best round brush I have owned. The cork grip genuinely stops my wrist aching on long blow-dries.'},
 {n:'Sofia M.',loc:'Porto',s:4,ht:'curly',b:'Linda e bem feita. As cerdas são firmes; demora um pouco a habituar, mas vale a pena.'},
 {n:'Daniel K.',loc:'Berlin',s:5,ht:'straight',b:'A beautiful object that actually works. You can feel the 1987 heritage — proper craftsmanship.'}
];
const HT_KEY={fine:'qo_fine',thick:'qo_thick',curly:'qo_curly',straight:'qo_straight'};
function initReviews(){
  const list=document.getElementById('rlist');if(!list)return;
  function L(k){const l=document.documentElement.lang||'en';return (T[l]&&T[l][k]!==undefined)?T[l][k]:k;}
  const avg=REVIEWS.reduce((a,r)=>a+r.s,0)/REVIEWS.length;
  const avgEl=document.querySelector('.reviews .ravg');if(avgEl)avgEl.textContent=avg.toFixed(1);
  const bars=document.getElementById('rbars');
  if(bars){let h='';for(let star=5;star>=1;star--){const c=REVIEWS.filter(r=>r.s===star).length;const pct=Math.round(c/REVIEWS.length*100);h+='<div class="rbar"><span class="rb-l">'+star+'★</span><span class="rb-t"><span style="width:'+pct+'%"></span></span><span class="rb-n">'+c+'</span></div>';}bars.innerHTML=h;}
  const filters=document.getElementById('rfilters');let active='all';
  function renderCards(){
    const rows=REVIEWS.filter(r=>active==='all'||r.ht===active);
    list.innerHTML=rows.map(r=>'<div class="rcard"><div class="rc-top"><span class="rc-av">'+r.n.charAt(0)+'</span><div><div class="rc-n">'+r.n+'</div><div class="rc-loc">'+r.loc+'</div></div><span class="rc-st">'+'★'.repeat(r.s)+'<span class="rc-off">'+'★'.repeat(5-r.s)+'</span></span></div><p class="rc-b">'+r.b+'</p><span class="rc-ht">'+L(HT_KEY[r.ht])+'</span></div>').join('');
  }
  const types=['all','fine','thick','curly','straight'];
  function renderChips(){if(!filters)return;filters.innerHTML=types.map(t=>'<button class="rchip'+(t===active?' on':'')+'" type="button" data-ht="'+t+'">'+L(t==='all'?'rf_all':HT_KEY[t])+'</button>').join('');filters.querySelectorAll('.rchip').forEach(c=>c.addEventListener('click',()=>{active=c.getAttribute('data-ht');renderChips();renderCards();}));}
  renderChips();renderCards();
  window.reviewsRerender=function(){renderChips();renderCards();};
}

/* ===== Find-your-brush quiz (high-ROI: Jones Road/Shein — discovery + email capture; prod -> Klaviyo/Shopify Forms) ===== */
const QUIZ_STEPS=[
 {key:'hair',q:'qq_hair',opts:[['fine','qo_fine'],['thick','qo_thick'],['curly','qo_curly'],['straight','qo_straight']]},
 {key:'material',q:'qq_mat',opts:[['cork','qo_cork'],['wood','qo_wood'],['either','qo_either']]},
 {key:'use',q:'qq_use',opts:[['blowdry','qo_blowdry'],['detangle','qo_detangle'],['finish','qo_finish'],['beard','qo_beard']]}
];
const QZ_PRODUCTS={
 round:{t:'E.Cork LARGO / Large',price:'€28,90',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/products/920.jpg?width=600',h:'ecork-largo-large',r:'qz_r_round'},
 paddle:{t:'PADDLE Cork / HE',price:'€29,04',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/products/908.jpg?width=600',h:'paddle-cork-he-doble-pua',r:'qz_r_paddle'},
 wood:{t:'PADDLE Wood / HE',price:'€25,41',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/products/907.jpg?width=600',h:'paddle-wood-he-double-pin',r:'qz_r_wood'},
 vent:{t:'Cepillo YoGa Aqua',price:'€13,19',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/products/937.jpg?width=600',h:'yoga-aqua-brush',r:'qz_r_vent'},
 beard:{t:'E.Cork LARGO / Mediano',price:'€26,90',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/products/916.jpg?width=600',h:'ecork-largo-medium',r:'qz_r_beard'}
};
function quizResultKey(a){if(a.use==='beard')return'beard';if(a.material==='wood')return'wood';if(a.use==='detangle'||a.hair==='curly')return'paddle';if(a.use==='finish')return'vent';return'round';}
function initQuiz(){
  const stage=document.getElementById('qzstage');if(!stage)return;
  const bar=document.getElementById('qzbar');
  const answers={};let step=0,inResult=false;
  function L(k){const l=document.documentElement.lang||'en';return (T[l]&&T[l][k]!==undefined)?T[l][k]:k;}
  function renderStep(){
    inResult=false;const s=QUIZ_STEPS[step];
    if(bar)bar.style.width=Math.round(step/QUIZ_STEPS.length*100)+'%';
    stage.innerHTML='<div class="qz-q">'+L(s.q)+'</div><div class="qz-opts">'+s.opts.map(o=>'<button class="qz-opt" type="button" data-v="'+o[0]+'">'+L(o[1])+'</button>').join('')+'</div>'+(step>0?'<button class="qz-back" type="button" data-back="1">'+L('qz_back')+'</button>':'');
    stage.querySelectorAll('.qz-opt').forEach(b=>b.addEventListener('click',()=>{answers[s.key]=b.getAttribute('data-v');step++;if(step<QUIZ_STEPS.length)renderStep();else renderResult();}));
    const back=stage.querySelector('[data-back]');if(back)back.addEventListener('click',()=>{step--;renderStep();});
  }
  function renderResult(){
    inResult=true;if(bar)bar.style.width='100%';
    const p=QZ_PRODUCTS[quizResultKey(answers)];
    stage.innerHTML='<div class="qz-result"><img src="'+p.img+'" alt=""><div><div class="upper qz-r-eye">'+L('qz_result_eye')+'</div><div class="qz-r-name serif">'+p.t+'</div><div class="qz-r-reason">'+L(p.r)+'</div><div class="qz-r-price">'+p.price+'</div><a class="btn" href="product.html?p='+p.h+'">'+L('qz_cta')+'</a></div></div><div class="qz-email"><h4>'+L('qz_email_h')+'</h4><p>'+L('qz_email_p')+'</p><div class="qz-email-row" id="qzrow"><input type="email" id="qzmail" placeholder="'+L('qz_email_ph')+'"><button class="btn dark" id="qzsend" type="button">'+L('qz_email_btn')+'</button></div><button class="qz-back" type="button" id="qzrestart">'+L('qz_restart')+'</button></div>';
    const send=document.getElementById('qzsend'),mail=document.getElementById('qzmail');
    send.addEventListener('click',()=>{if(mail.value&&/.+@.+\..+/.test(mail.value)){document.getElementById('qzrow').innerHTML='<div class="qz-done">'+L('qz_email_done')+'</div>';}else{mail.focus();mail.style.borderColor='var(--cork-d)';}});
    const rs=document.getElementById('qzrestart');if(rs)rs.addEventListener('click',()=>{step=0;Object.keys(answers).forEach(k=>delete answers[k]);renderStep();});
  }
  window.quizRerender=function(){if(inResult)renderResult();else renderStep();};
  renderStep();
}

/* ===== Lookbook (shoppable hotspots → quick-view) ===== */
const LB_PRODUCTS={
 round:{nm:'E.Cork LARGO / Large',pr:'€28,90',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/products/920.jpg?width=500',h:'ecork-largo-large'},
 paddle:{nm:'PADDLE Cork / HE',pr:'€29,04',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/products/908.jpg?width=500',h:'paddle-cork-he-doble-pua'},
 vent:{nm:'Cepillo YoGa Aqua',pr:'€13,19',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/products/937.jpg?width=500',h:'yoga-aqua-brush'},
 roller:{nm:'Ibiza EX 6 · Hybrid',pr:'€47,19',img:'https://cdn.shopify.com/s/files/1/0769/8166/6137/files/9_724f958c-d210-4815-8d1b-3438b521cb40.png?width=500',h:'ibiza-ex-6-hybrid'}
};
function initLookbook(){
  const modal=document.getElementById('lbmodal'); if(!modal)return;
  const img=document.getElementById('lbimg'),nm=document.getElementById('lbnm'),pr=document.getElementById('lbpr');
  function open(key){const p=LB_PRODUCTS[key]; if(!p)return; img.src=p.img; nm.textContent=p.nm; pr.textContent=p.pr; var lk=document.getElementById('lblink'); if(lk)lk.href='product.html'+(p.h?'?p='+p.h:''); modal.hidden=false; modal.classList.add('show');}
  function close(){modal.classList.remove('show'); modal.hidden=true;}
  document.querySelectorAll('.hot').forEach(function(h){h.addEventListener('click',function(){open(h.getAttribute('data-prod'));});});
  var x=document.getElementById('lbx'); if(x)x.addEventListener('click',close);
  modal.addEventListener('click',function(e){if(e.target===modal)close();});
  document.addEventListener('keydown',function(e){if(e.key==='Escape'&&modal.classList.contains('show'))close();});
  var hv=document.querySelector('.lb-hero video.bg');
  if(hv){var rm=matchMedia('(prefers-reduced-motion:reduce)').matches;var sd=navigator.connection&&navigator.connection.saveData;if(rm||sd){hv.style.display='none';var fb=document.querySelector('.lb-hero .bg-fallback');if(fb)fb.style.display='block';}else{var pp=hv.play();if(pp&&pp.catch)pp.catch(function(){});}}
}

/* ===== Dynamic PDP — wypelnia stronę produktu z ?p=<handle> (realny katalog) ===== */
function initPDP(){
  try{
    var h=new URLSearchParams(location.search).get('p');
    if(!h||!window.CATALOG)return;
    var p=window.CATALOG.find(function(x){return x.h===h;});
    if(!p)return;
    var name=p.t, price='€'+Number(p.p).toFixed(2).replace('.',',');
    var imgs=(p.imgs&&p.imgs.length)?p.imgs:[p.img];
    var h1=document.querySelector('.pinfo h1');
    if(h1){var w=name.split(' ');var last=w.length>1?w.pop():'';h1.innerHTML=w.join(' ')+(last?' <em>'+last+'</em>':'');h1.removeAttribute('data-i');}
    var pr=document.querySelector('.pinfo .price');if(pr)pr.innerHTML=price;
    var cr=document.querySelector('[data-i="pd_crumb"]');if(cr){cr.textContent=name;cr.removeAttribute('data-i');}
    var kick=document.querySelector('.pinfo .kick');if(kick){kick.textContent=p.line.charAt(0).toUpperCase()+p.line.slice(1);kick.removeAttribute('data-i');}
    if(p.d){var pd=document.querySelector('.pdesc');if(pd){pd.textContent=p.d;pd.removeAttribute('data-i');}}
    var img=document.getElementById('mainimg');if(img){img.src=imgs[0]+'?width=1100';img.alt=name+' — Regincós Hair';}
    var altName=name.replace(/"/g,'');
    var thumbs=document.querySelector('.thumbs');
    if(thumbs){
      thumbs.innerHTML=imgs.map(function(u,i){return '<button class="thumb'+(i===0?' on':'')+'" type="button" aria-label="'+altName+' — view '+(i+1)+'" data-full="'+u+'?width=1100"><img src="'+u+'?width=200" alt=""></button>';}).join('');
      thumbs.querySelectorAll('.thumb').forEach(function(b){b.addEventListener('click',function(){thumbs.querySelectorAll('.thumb').forEach(function(x){x.classList.remove('on');});b.classList.add('on');var m=document.getElementById('mainimg');if(m){m.classList.add('swapping');setTimeout(function(){m.src=b.getAttribute('data-full');m.classList.remove('swapping');},180);}});});
      thumbs.style.display='';
    }
    if(p.v&&p.v.length){var row=document.querySelector('.opt .row');if(row)row.innerHTML=p.v.map(function(v,i){return '<button type="button" class="'+(i===0?'on':'')+'">'+v+'</button>';}).join('');var opts=document.querySelectorAll('.opt');if(opts[1])opts[1].style.display='none';}
    var v360=document.getElementById('v360btn');
    if(p.vid){var mv=document.getElementById('v360');if(mv){var s=mv.querySelector('source');if(s)s.src=p.vid;mv.setAttribute('poster',imgs[0]+'?width=1100');}if(v360)v360.style.display='';}
    else if(v360)v360.style.display='none';
    var sbn=document.querySelector('.stickybar .sb-name');if(sbn){sbn.textContent=name;sbn.removeAttribute('data-i');}
    var sbp=document.querySelector('.stickybar .sb-price');if(sbp)sbp.textContent=price;
    document.title=name+' — Regincós Hair';
    /* ===== SEO: meta description, Open Graph, JSON-LD Product schema (real catalog data) ===== */
    var sdesc=(p.d||(name+' — handcrafted cork & wood hair brush by Regincós, Spain since 1987.')).slice(0,160);
    var purl=location.href, ogimg=imgs[0]+'?width=1200';
    function _m(sel,mk){var el=document.head.querySelector(sel);if(!el){el=mk();document.head.appendChild(el);}return el;}
    function _n(n){return _m('meta[name="'+n+'"]',function(){var m=document.createElement('meta');m.setAttribute('name',n);return m;});}
    function _p(pr){return _m('meta[property="'+pr+'"]',function(){var m=document.createElement('meta');m.setAttribute('property',pr);return m;});}
    _n('description').setAttribute('content',sdesc);
    _m('link[rel="canonical"]',function(){var l=document.createElement('link');l.setAttribute('rel','canonical');return l;}).setAttribute('href',purl);
    _p('og:type').setAttribute('content','product');
    _p('og:title').setAttribute('content',name+' — Regincós Hair');
    _p('og:description').setAttribute('content',sdesc);
    _p('og:image').setAttribute('content',ogimg);
    _p('og:url').setAttribute('content',purl);
    _n('twitter:card').setAttribute('content','summary_large_image');
    var ld={'@context':'https://schema.org/','@type':'Product',name:name,image:imgs.map(function(u){return u+'?width=1200';}),description:sdesc,brand:{'@type':'Brand',name:'Regincós Hair'},offers:{'@type':'Offer',priceCurrency:'EUR',price:Number(p.p).toFixed(2),availability:'https://schema.org/InStock',url:purl}};
    var sc=document.getElementById('ld-product');if(!sc){sc=document.createElement('script');sc.type='application/ld+json';sc.id='ld-product';document.head.appendChild(sc);}
    sc.textContent=JSON.stringify(ld);
  }catch(e){}
}

/* ===== Materials triptych autoplay ===== */
function initMaterials(){
  var cells=document.querySelectorAll('.mat-cell video, .mprod video'); if(!cells.length)return;
  var rm=matchMedia('(prefers-reduced-motion:reduce)').matches;var sd=navigator.connection&&navigator.connection.saveData;
  if(rm||sd)return;
  cells.forEach(function(v){var p=v.play();if(p&&p.catch)p.catch(function(){});});
}

/* ===== Cart drawer (prototype — localStorage; produkcyjnie -> Shopify AJAX cart) ===== */
var FREE_SHIP=45, _toastTmr;
function cartLang(){return document.documentElement.lang||'en';}
function cartT(k){var l=cartLang();return (T[l]&&T[l][k]!==undefined)?T[l][k]:(T.en[k]!==undefined?T.en[k]:k);}
function eurFmt(n){return '€'+Number(n||0).toFixed(2).replace('.',',');}
function cartGet(){try{return JSON.parse(localStorage.getItem('rg_cart')||'[]');}catch(e){return [];}}
function cartSave(c){try{localStorage.setItem('rg_cart',JSON.stringify(c));}catch(e){}cartBadge();cartRender();}
function cartCount(){return cartGet().reduce(function(a,x){return a+(x.q||1);},0);}
function cartTotal(){return cartGet().reduce(function(a,x){return a+(Number(x.p)||0)*(x.q||1);},0);}
function cartBadge(){var n=cartCount();document.querySelectorAll('[title="cart"]').forEach(function(s){s.textContent='⛒ '+n;s.classList.toggle('has',n>0);});}
function cartImg(u){u=u||'';return u+((u&&u.indexOf('?')<0)?'?width=160':'');}
function cartAdd(item){
  if(!item||item.p==null||!(Number(item.p)>0))return;
  var c=cartGet();var key=item.h+'|'+(item.v||'');
  var ex=c.find(function(x){return (x.h+'|'+(x.v||''))===key;});
  if(ex){ex.q=(ex.q||1)+(item.q||1);}else{c.push({h:item.h,t:item.t,p:Number(item.p),img:item.img,v:item.v||'',q:item.q||1});}
  cartSave(c);cartToast(cartT('cart_added'));cartOpen();
}
function cartSetQty(i,q){var c=cartGet();if(!c[i])return;c[i].q=Math.max(1,q);cartSave(c);}
function cartRemove(i){var c=cartGet();c.splice(i,1);cartSave(c);}
function cartEnsureDOM(){
  if(document.getElementById('cartDrawer'))return;
  var ov=document.createElement('div');ov.className='cart-ov';ov.id='cartOv';ov.hidden=true;ov.addEventListener('click',cartClose);
  var d=document.createElement('aside');d.className='cart-dr';d.id='cartDrawer';d.setAttribute('aria-hidden','true');d.setAttribute('aria-label','Cart');d.setAttribute('role','dialog');
  d.innerHTML='<div class="cd-top"><span class="cd-ttl serif"></span><button class="cd-x" type="button" aria-label="Close">✕</button></div>'+
    '<div class="cd-ship" id="cdShip"></div>'+
    '<div class="cd-items" id="cdItems"></div>'+
    '<div class="cd-foot"><div class="cd-sub"><span class="cd-sublab"></span><span id="cdTotal"></span></div><button class="btn block" id="cdCheckout" type="button"></button><div class="cd-note"></div></div>';
  document.body.appendChild(ov);document.body.appendChild(d);
  d.querySelector('.cd-x').addEventListener('click',cartClose);
  d.querySelector('#cdCheckout').addEventListener('click',function(){if(cartGet().length)cartToast(cartT('cart_note'));});
  d.querySelector('#cdItems').addEventListener('click',function(e){
    var b=e.target.closest('[data-act]');if(!b)return;
    var i=parseInt(b.getAttribute('data-i2'),10);var act=b.getAttribute('data-act');var c=cartGet();if(!c[i]&&act!=='rm')return;
    if(act==='inc')cartSetQty(i,(c[i].q||1)+1);
    else if(act==='dec')cartSetQty(i,(c[i].q||1)-1);
    else if(act==='rm')cartRemove(i);
  });
  if(!document.getElementById('cartToast')){var t=document.createElement('div');t.className='cart-toast';t.id='cartToast';t.setAttribute('role','status');document.body.appendChild(t);}
  window.cartRerender=cartRender;
}
function cartRender(){
  var d=document.getElementById('cartDrawer');if(!d)return;
  var c=cartGet();
  d.querySelector('.cd-ttl').textContent=cartT('cart_title');
  d.querySelector('.cd-sublab').textContent=cartT('cart_sub');
  d.querySelector('.cd-note').textContent=cartT('cart_note');
  d.querySelector('#cdCheckout').textContent=cartT('cart_checkout');
  var items=d.querySelector('#cdItems'),ship=d.querySelector('#cdShip'),foot=d.querySelector('.cd-foot');
  if(!c.length){
    items.innerHTML='<div class="cd-empty"><p>'+cartT('cart_empty')+'</p><a class="btn" href="collection.html">'+cartT('cart_empty_cta')+'</a></div>';
    ship.style.display='none';foot.style.display='none';return;
  }
  foot.style.display='';ship.style.display='';
  items.innerHTML=c.map(function(x,i){
    return '<div class="cd-item"><img src="'+cartImg(x.img)+'" alt="" loading="lazy"><div class="cd-mid"><div class="cd-n serif">'+x.t+'</div>'+(x.v?'<div class="cd-v">'+x.v+'</div>':'')+'<div class="cd-qr"><div class="cd-qty"><button type="button" data-act="dec" data-i2="'+i+'" aria-label="−">−</button><span>'+x.q+'</span><button type="button" data-act="inc" data-i2="'+i+'" aria-label="+">+</button></div><button class="cd-rm" type="button" data-act="rm" data-i2="'+i+'">'+cartT('cart_remove')+'</button></div></div><div class="cd-p">'+eurFmt(Number(x.p)*x.q)+'</div></div>';
  }).join('');
  var total=cartTotal(),pct=Math.min(100,Math.round(total/FREE_SHIP*100));
  if(total>=FREE_SHIP){ship.innerHTML='<div class="cd-shiptxt ok">✓ '+cartT('cart_ship_free')+'</div><div class="cd-bar"><i style="width:100%"></i></div>';}
  else{ship.innerHTML='<div class="cd-shiptxt">'+cartT('cart_ship_a')+' <b>'+eurFmt(FREE_SHIP-total)+'</b> '+cartT('cart_ship_b')+'</div><div class="cd-bar"><i style="width:'+pct+'%"></i></div>';}
  d.querySelector('#cdTotal').textContent=eurFmt(total);
}
function cartOpen(){cartEnsureDOM();cartRender();var d=document.getElementById('cartDrawer'),ov=document.getElementById('cartOv');ov.hidden=false;void d.offsetWidth;d.classList.add('show');ov.classList.add('show');d.setAttribute('aria-hidden','false');document.body.style.overflow='hidden';}
function cartClose(){var d=document.getElementById('cartDrawer'),ov=document.getElementById('cartOv');if(!d)return;d.classList.remove('show');ov.classList.remove('show');d.setAttribute('aria-hidden','true');document.body.style.overflow='';setTimeout(function(){ov.hidden=true;},320);}
function cartToast(msg){cartEnsureDOM();var t=document.getElementById('cartToast');if(!t)return;t.textContent=msg;t.classList.add('show');clearTimeout(_toastTmr);_toastTmr=setTimeout(function(){t.classList.remove('show');},1800);}
function _catProd(h){return (h&&window.CATALOG)?window.CATALOG.find(function(x){return x.h===h;}):null;}
function initCart(){
  cartEnsureDOM();cartBadge();
  document.querySelectorAll('[title="cart"]').forEach(function(s){s.style.cursor='pointer';s.addEventListener('click',cartOpen);});
  document.addEventListener('keydown',function(e){if(e.key==='Escape')cartClose();});
  /* PDP buy buttons */
  var h=new URLSearchParams(location.search).get('p');var pp=_catProd(h);
  if(pp){
    document.querySelectorAll('.buyrow .btn, .stickybar .btn').forEach(function(btn){
      btn.addEventListener('click',function(e){
        e.preventDefault();
        var qel=document.getElementById('q');var qty=qel?(parseInt(qel.textContent,10)||1):1;
        var onv=document.querySelector('.opt .row button.on');var variant=onv?onv.textContent.trim():'';
        cartAdd({h:pp.h,t:pp.t,p:pp.p,img:(pp.imgs&&pp.imgs[0])||pp.img,v:variant,q:qty});
      });
    });
  }
  /* collection / related cards: the hover "add" overlay */
  document.querySelectorAll('.prod .add').forEach(function(add){
    add.addEventListener('click',function(e){
      e.preventDefault();e.stopPropagation();
      var card=add.closest('.prod');if(!card)return;
      var href=card.getAttribute('href')||'';var m=href.match(/[?&]p=([^&]+)/);var hh=m?decodeURIComponent(m[1]):null;
      var p=_catProd(hh);
      if(p){cartAdd({h:p.h,t:p.t,p:p.p,img:(p.imgs&&p.imgs[0])||p.img,v:'',q:1});return;}
      var t=(card.querySelector('h4')||{}).textContent||'Brush';
      var pr=parseFloat(card.getAttribute('data-price')||'0')||0;
      if(!pr){var px=card.querySelector('.px');if(px)pr=parseFloat((px.textContent||'').replace('€','').replace(',','.'))||0;}
      var im=(card.querySelector('img')||{}).src||'';
      cartAdd({h:href||t,t:t,p:pr,img:im,v:'',q:1});
    });
  });
  /* PDP bundle "add all three" */
  var bn=document.getElementById('bnbtn');
  if(bn){bn.addEventListener('click',function(){
    document.querySelectorAll('.bn-item').forEach(function(it){
      var t=(it.querySelector('.bn-n')||{}).textContent||'Item';
      var pr=parseFloat(((it.querySelector('.bn-p')||{}).textContent||'').replace('€','').replace(',','.'))||0;
      var im=(it.querySelector('img')||{}).src||'';
      cartAdd({h:'bundle-'+t,t:t,p:pr,img:im,v:'',q:1});
    });
  });}
}

/* ===== Mobile nav (hamburger + slide-down) — navlinks are display:none < 900px ===== */
function initNav(){
  var navrow=document.querySelector('nav .nav');var links=document.querySelector('.navlinks');var navright=document.querySelector('.navright');
  if(!navrow||!links||!navright||document.getElementById('mobnav'))return;
  var burger=document.createElement('button');
  burger.className='navburger';burger.type='button';burger.setAttribute('aria-label','Menu');burger.setAttribute('aria-expanded','false');burger.setAttribute('aria-controls','mobnav');
  burger.innerHTML='<span></span><span></span><span></span>';
  navright.insertBefore(burger,navright.firstChild);
  var panel=document.createElement('div');panel.className='mobnav';panel.id='mobnav';panel.hidden=true;
  panel.innerHTML='<div class="mobnav-in">'+links.innerHTML+'<a href="index.html" data-i="cl_home">Home</a><a href="our-story.html" data-i="sp_btn2">Our story</a></div>';
  document.querySelector('nav').appendChild(panel);
  function close(){panel.classList.remove('show');burger.classList.remove('on');burger.setAttribute('aria-expanded','false');setTimeout(function(){if(!panel.classList.contains('show'))panel.hidden=true;},260);}
  function open(){panel.hidden=false;void panel.offsetWidth;panel.classList.add('show');burger.classList.add('on');burger.setAttribute('aria-expanded','true');}
  burger.addEventListener('click',function(){if(panel.classList.contains('show'))close();else open();});
  panel.querySelectorAll('a').forEach(function(a){a.addEventListener('click',close);});
  window.addEventListener('resize',function(){if(window.innerWidth>900)close();});
}
